+func requireEqualProtoStructMap(t *testing.T, expected map[string]any, actual *structpb.Struct) {
+	t.Helper()
+	if expected == nil {
+		require.Nil(t, actual)
+		return
+	}
+	require.True(t, reflect.DeepEqual(expected, actual.AsMap()))
+}

